import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import './App.css';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5000/api';

function App() {
  const [notes, setNotes] = useState([]);
  const [currentNote, setCurrentNote] = useState({
    title: '',
    content: '',
    category: 'General',
    source: 'text'
  });
  const [isListening, setIsListening] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [editingId, setEditingId] = useState(null);
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [isSpeaking, setIsSpeaking] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [isRecordingScreen, setIsRecordingScreen] = useState(false);
  const [videoFile, setVideoFile] = useState(null);
  const [isProcessingVideo, setIsProcessingVideo] = useState(false);
  const [videoProgress, setVideoProgress] = useState('');
  const [activeTab, setActiveTab] = useState('text');
  const [isGeneratingSummary, setIsGeneratingSummary] = useState(false);
  const [viewingNote, setViewingNote] = useState(null);
  const [translatedContent, setTranslatedContent] = useState({});
  const [isTranslating, setIsTranslating] = useState(false);
  const [showChat, setShowChat] = useState(false);
  const [chatMessages, setChatMessages] = useState([]);
  const [chatInput, setChatInput] = useState('');
  const [isAIThinking, setIsAIThinking] = useState(false);
  const [loading, setLoading] = useState(false);

  const recognitionRef = useRef(null);
  const synthRef = useRef(window.speechSynthesis);
  const screenStreamRef = useRef(null);

  const categories = [
    'General', 'Math', 'Science', 'History',
    'Literature', 'Programming', 'Languages', 'Other'
  ];

  // ================= SPEECH RECOGNITION =================
  useEffect(() => {
    if ('webkitSpeechRecognition' in window || 'SpeechRecognition' in window) {
      const SpeechRecognition =
        window.SpeechRecognition || window.webkitSpeechRecognition;

      const recognition = new SpeechRecognition();
      recognition.continuous = true;
      recognition.interimResults = true;

      recognition.onresult = (event) => {
        let finalTranscript = '';
        for (let i = event.resultIndex; i < event.results.length; i++) {
          if (event.results[i].isFinal) {
            finalTranscript += event.results[i][0].transcript + ' ';
          }
        }
        if (finalTranscript) {
          setCurrentNote(prev => ({
            ...prev,
            content: prev.content + finalTranscript
          }));
        }
      };

      recognition.onerror = (e) => {
        setError(`Speech error: ${e.error}`);
        setIsListening(false);
      };

      recognition.onend = () => setIsListening(false);

      recognitionRef.current = recognition;
    }
  }, []);

  // Cleanup speech synthesis
  useEffect(() => {
    return () => synthRef.current.cancel();
  }, []);

  // ================= FETCH NOTES =================
  useEffect(() => {
    fetchNotes();
  }, [selectedCategory]);

  const fetchNotes = async () => {
    try {
      setLoading(true);
      const params = new URLSearchParams();
      if (selectedCategory !== 'All') params.append('category', selectedCategory);
      if (searchQuery) params.append('search', searchQuery);

      const res = await axios.get(`${API_URL}/notes?${params}`);
      setNotes(res.data);
    } catch {
      setError('Failed to fetch notes');
    } finally {
      setLoading(false);
    }
  };

  // ================= AI CHAT =================
  const askAIAboutNotes = async () => {
    if (!chatInput.trim()) return;

    setChatMessages(prev => [...prev, { role: 'user', content: chatInput }]);
    setChatInput('');
    setIsAIThinking(true);

    try {
      const res = await axios.post(`${API_URL}/chat`, {
        question: chatInput,
        allNotes: viewingNote ? [viewingNote] : notes
      });

      setChatMessages(prev => [
        ...prev,
        { role: 'assistant', content: res.data.response }
      ]);
    } catch {
      setError('AI chat failed');
    } finally {
      setIsAIThinking(false);
    }
  };

  // ================= SMART SUMMARY =================
  const generateSmartNotes = async () => {
    if (!currentNote.content) return;
    setIsGeneratingSummary(true);

    try {
      const res = await axios.post(`${API_URL}/generate-summary`, {
        content: currentNote.content
      });

      const smartText = `
📌 SUMMARY:
${res.data.summary}

🔑 KEYWORDS:
${res.data.keywords.join(', ')}

📝 ORIGINAL CONTENT:
${currentNote.content}
      `;

      setCurrentNote(prev => ({ ...prev, content: smartText }));
      setSuccess('Smart summary generated!');
    } catch {
      setError('Summary generation failed');
    } finally {
      setIsGeneratingSummary(false);
    }
  };

  // ================= VOICE INPUT =================
  const toggleListening = () => {
    if (!recognitionRef.current) {
      setError('Speech recognition not supported');
      return;
    }

    if (isListening) {
      recognitionRef.current.stop();
    } else {
      recognitionRef.current.start();
      setCurrentNote(prev => ({ ...prev, source: 'voice' }));
    }
    setIsListening(!isListening);
  };

  // ================= SCREEN RECORDING =================
  const startScreenRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({
        video: true,
        audio: true
      });

      screenStreamRef.current = stream;
      recognitionRef.current.start();
      setIsRecordingScreen(true);
      setVideoProgress('Recording screen...');

      stream.getVideoTracks()[0].onended = stopScreenRecording;
    } catch (e) {
      setError(e.message);
    }
  };

  const stopScreenRecording = () => {
    screenStreamRef.current?.getTracks().forEach(t => t.stop());
    recognitionRef.current.stop();
    setIsRecordingScreen(false);
    setVideoProgress('');
    setSuccess('Screen recording completed!');
  };

  // ================= VIDEO UPLOAD =================
  const handleVideoUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;

    setVideoFile(file);
    setIsProcessingVideo(true);

    const formData = new FormData();
    formData.append('video', file);

    try {
      await axios.post(`${API_URL}/upload-video`, formData);
      setCurrentNote(prev => ({
        ...prev,
        content: prev.content + `\n[Video Uploaded: ${file.name}]`,
        source: 'video'
      }));
      setSuccess('Video uploaded');
    } catch {
      setError('Video upload failed');
    } finally {
      setIsProcessingVideo(false);
    }
  };

  // ================= TEXT TO SPEECH =================
  const speakText = (text) => {
    if (!text) return;

    if (isSpeaking) {
      synthRef.current.cancel();
      setIsSpeaking(false);
      return;
    }

    const utter = new SpeechSynthesisUtterance(text);
    utter.onstart = () => setIsSpeaking(true);
    utter.onend = () => setIsSpeaking(false);

    synthRef.current.speak(utter);
  };

  // ================= SAVE NOTE =================
  const saveNote = async () => {
    if (!currentNote.title || !currentNote.content) {
      setError('Title and content required');
      return;
    }

    try {
      editingId
        ? await axios.put(`${API_URL}/notes/${editingId}`, currentNote)
        : await axios.post(`${API_URL}/notes`, currentNote);

      setSuccess(editingId ? 'Note updated' : 'Note saved');
      setCurrentNote({ title: '', content: '', category: 'General', source: 'text' });
      setEditingId(null);
      fetchNotes();
    } catch {
      setError('Save failed');
    }
  };

  // ================= DELETE =================
  const deleteNote = async (id) => {
    await axios.delete(`${API_URL}/notes/${id}`);
    fetchNotes();
  };

  // ================= DOWNLOAD =================
  const downloadNote = (note) => {
    const blob = new Blob([note.content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${note.title}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  return (
    <div className="app">
      <h1>📚 Smart Note-Taking Assistant</h1>

      {error && <div className="alert error">{error}</div>}
      {success && <div className="alert success">{success}</div>}

      <input
        placeholder="Title"
        value={currentNote.title}
        onChange={e => setCurrentNote({ ...currentNote, title: e.target.value })}
      />

      <textarea
        placeholder="Content"
        rows="10"
        value={currentNote.content}
        onChange={e => setCurrentNote({ ...currentNote, content: e.target.value })}
      />

      <button onClick={toggleListening}>🎤 Voice</button>
      <button onClick={generateSmartNotes}>✨ Smart Summary</button>
      <button onClick={() => speakText(currentNote.content)}>
  {isSpeaking ? '⏹ Stop' : '🔊 Read Aloud'}
</button>
      <button onClick={saveNote}>💾 Save</button>

      <h2>My Notes</h2>
      {notes.map(note => (
        <div key={note._id}>
          <h3>{note.title}</h3>
          <button onClick={() => downloadNote(note)}>⬇ Download</button>
          <button onClick={() => deleteNote(note._id)}>🗑 Delete</button>
        </div>
      ))}
    </div>
  );
}

export default App;
